// 骨骼世界矩阵计算伪代码
interface Bone {
  name: string;
  parentIndex: number;  // -1 表示根骨骼
  localPosition: Vec3;
  localRotation: Quat;
  localScale: Vec3;
}

// 从根到叶遍历
for (let i = 0; i < bones.length; i++) {
  const bone = bones[i];
  const localMatrix = Mat4.fromRTS(bone.localRotation, bone.localPosition, bone.localScale);
  if (bone.parentIndex >= 0) {
    worldMatrix[i] = Mat4.multiply(worldMatrix[bone.parentIndex], localMatrix);
  } else {
    worldMatrix[i] = localMatrix;
  }
}

// 逆绑定矩阵的作用
// restPos: 顶点在模型空间的初始位置（绑定姿态下）
// boneWorld_bind: 骨骼在绑定姿态下的世界矩阵
// invBindMatrix = inverse(boneWorld_bind)
// boneLocalPos = invBindMatrix * restPos
// 
// 当骨骼移动后，新的世界矩阵可以重新变换回去:
// newPos = currentBoneWorld * invBindMatrix * restPos

// FK 计算过程
// 根骨骼 (Hips)     -> worldMatrix[0] = localMatrix[0]
//   +-- Spine        -> worldMatrix[1] = worldMatrix[0] * localMatrix[1]
//   |   +-- Head     -> worldMatrix[2] = worldMatrix[1] * localMatrix[2]
//   |   +-- L_UpperArm -> worldMatrix[3] = worldMatrix[1] * localMatrix[3]
//   |   |   +-- L_ForeArm -> worldMatrix[4] = worldMatrix[3] * localMatrix[4]
//   |   +-- R_UpperArm -> ...
//   +-- L_UpperLeg   -> worldMatrix[5] = worldMatrix[0] * localMatrix[5]
//   |   +-- L_LowerLeg -> worldMatrix[6] = worldMatrix[5] * localMatrix[6]
//   +-- R_UpperLeg   -> ...

// 2D 仿射变换矩阵 (3x3)
// | cos(theta)*sx  -sin(theta)*sx  tx |
// | sin(theta)*sy   cos(theta)*sy  ty |
// | 0               0              1  |
//
// 其中:
//   theta = 旋转角度
//   sx, sy = X/Y 方向缩放
//   tx, ty = 平移分量

function fromRTS(out: Mat3, rotation: number, tx: number, ty: number, sx: number, sy: number) {
  const cos = Math.cos(rotation);
  const sin = Math.sin(rotation);
  out[0] = cos * sx;  out[1] = sin * sx;  out[2] = 0;
  out[3] = -sin * sy; out[4] = cos * sy;  out[5] = 0;
  out[6] = tx;        out[7] = ty;         out[8] = 1;
}
